import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class SecureCommandInjectionExample {

    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a command to execute: ");
        String command = reader.readLine();

        // Sanitize user input by only allowing alphanumeric characters and whitelisted symbols
        if (!command.matches("[a-zA-Z0-9\\s.,_-]+")) {
            System.out.println("Invalid command. Please provide a valid input.");
            return;
        }

        // Execute the sanitized command
        Process process = Runtime.getRuntime().exec(new String[]{"ping", command});

        BufferedReader outputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String line;
        while ((line = outputReader.readLine()) != null) {
            System.out.println(line);
        }
    }
}

